"""Run from your insightforge project root:  python3 install_stage6.py"""
import base64
from pathlib import Path
ROOT = Path(__file__).parent
FILES = {
  "backend/app/observability/usage_tracker.py": "",
  "backend/app/api/routes/observability.py": "",
  "backend/app/services/orchestrator.py": "",
  "backend/app/main.py": "",
  "backend/tests/test_usage_tracker.py": ""
}
for rel, b64 in FILES.items():
    p = ROOT / rel
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_bytes(base64.b64decode(b64))
    print(f"  wrote {rel}")
print("\nDone! Now run: make test")